def _blank_legacy():
    return [[0 for _ in range(LEGACY_SRC_WIDTH)] for _ in range(LEGACY_SRC_HEIGHT)]

def _draw_part(grid, part_id, row, col, h=8, w=8, xflip=False):
    part = PARTS.get(int(part_id)) or PARTS.get(0)
    for y in range(h):
        for x in range(w):
            sx = (w - 1 - x) if xflip else x
            yy = row + y
            xx = col + x
            if 0 <= yy < LEGACY_SRC_HEIGHT and 0 <= xx < LEGACY_SRC_WIDTH:
                grid[yy][xx] = 1 if part[y][sx] else 0

def legacy_grid_to_370_bitmap(grid, row_offset=LEGACY_ROW_OFFSET, col_offset=LEGACY_COL_OFFSET):
    out = [['.' for _ in range(COLS)] for _ in range(ROWS)]
    for y in range(LEGACY_SRC_HEIGHT):
        yy = y + row_offset
        if yy < 0 or yy >= ROWS:
            continue
        for x in range(LEGACY_SRC_WIDTH):
            xx = x + col_offset
            if xx < 0 or xx >= COLS:
                continue
            if grid[y][x]:
                out[yy][xx] = '#'
    return [''.join(row) for row in out]

def compose_part_bitmap(leye=1, reye=1, mouth=1, cheek=0, part_page_offset=True):
    log.info('FACE_PARTS', 'compose', leye=leye, reye=reye, mouth=mouth, cheek=cheek, part_page_offset=part_page_offset)
    # Part page is shifted one LED upward relative to full legacy faces.
    row_offset = max(0, LEGACY_ROW_OFFSET - 1) if part_page_offset else LEGACY_ROW_OFFSET
    g = _blank_legacy()
    _draw_part(g, 100 + int(leye), 0, 0, 8, 8, False)
    _draw_part(g, 200 + int(reye), 0, 10, 8, 8, False)
    _draw_part(g, 300 + int(mouth), 8, 5, 8, 8, False)
    if int(cheek) > 0:
        _draw_part(g, 400 + int(cheek), 8, 14, 4, 4, False)
        _draw_part(g, 400 + int(cheek), 8, 0, 4, 4, True)
    return legacy_grid_to_370_bitmap(g, row_offset=row_offset, col_offset=LEGACY_COL_OFFSET)
